import React, { useState, useMemo } from 'react';
import useAgileBloomStore from '../store/useAgileBloomStore';
import { useAgileBloomChat } from '../hooks/useAgileBloomChat';
import { QuestionItemCard } from './QuestionItemCard';
import { QuestionStatus, ExpertRole } from '../types';
import { Lightbulb, ChevronDown, CheckSquare, XSquare, Loader2, MessageSquare } from 'lucide-react';
import { BULK_ACTION_DELAY_MS } from '../constants';

// An ExpertGroup component to keep the main component cleaner
const ExpertQuestionGroup: React.FC<{
  expert: ReturnType<typeof useAgileBloomStore.getState>['experts'][string];
  questions: ReturnType<typeof useAgileBloomStore.getState>['trackedQuestions'];
  selectedQuestionIds: string[];
  onToggleSelection: (id: string) => void;
  onSelectAll: (ids: string[]) => void;
  onDeselectAll: (ids: string[]) => void;
  onDiscuss: (id: string) => void;
  onMarkAddressed: (id: string) => void;
  onDismiss: (id: string) => void;
  isDisabled: boolean;
}> = ({ expert, questions, selectedQuestionIds, onToggleSelection, onSelectAll, onDeselectAll, onDiscuss, onMarkAddressed, onDismiss, isDisabled }) => {
  const [isCollapsed, setIsCollapsed] = useState(false);

  const expertQuestions = useMemo(() => questions.filter(q => q.expertRole === expert.name), [questions, expert.name]);
  const expertQuestionIds = useMemo(() => expertQuestions.map(q => q.id), [expertQuestions]);

  const areAllSelected = useMemo(() => expertQuestionIds.length > 0 && expertQuestionIds.every(id => selectedQuestionIds.includes(id)), [expertQuestionIds, selectedQuestionIds]);

  if (expertQuestions.length === 0) {
    return null; // Don't render group if expert has no questions
  }

  const handleSelectAllToggle = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.checked) {
      onSelectAll(expertQuestionIds);
    } else {
      onDeselectAll(expertQuestionIds);
    }
  };

  return (
    <div className="bg-[#333e48]/50 rounded-lg border border-[#5c6f7e]">
      <header 
        className="p-3 flex items-center justify-between cursor-pointer hover:bg-[#333e48] transition-colors rounded-t-lg"
        onClick={() => setIsCollapsed(!isCollapsed)}
      >
        <div className="flex items-center gap-2">
            <input
                type="checkbox"
                checked={areAllSelected}
                onChange={handleSelectAllToggle}
                onClick={(e) => e.stopPropagation()} // Prevent header click from toggling collapse
                disabled={isDisabled}
                className="h-4 w-4 rounded bg-[#5c6f7e] border-[#95aac0] text-[#c36e26] focus:ring-[#e2a32d] cursor-pointer disabled:cursor-not-allowed"
                title={`Select all questions from ${expert.name}`}
            />
            <span className="text-lg">{expert.emoji}</span>
            <span className="font-semibold text-gray-200">{expert.name}</span>
            <span className="text-xs font-mono bg-[#5c6f7e] text-[#e2a32d] px-1.5 py-0.5 rounded-full">{expertQuestions.length}</span>
        </div>
        <ChevronDown size={20} className={`text-[#95aac0] transition-transform ${isCollapsed ? '-rotate-90' : ''}`} />
      </header>
      {!isCollapsed && (
        <div className="p-2 space-y-2 border-t border-[#5c6f7e]">
          {expertQuestions.sort((a, b) => a.timestamp - b.timestamp).map(q => (
            <QuestionItemCard
              key={q.id}
              question={q}
              isSelected={selectedQuestionIds.includes(q.id)}
              onToggleSelection={onToggleSelection}
              onDiscuss={onDiscuss}
              onMarkAddressed={onMarkAddressed}
              onDismiss={onDismiss}
              isDisabled={isDisabled}
            />
          ))}
        </div>
      )}
    </div>
  );
};


export const TrackedQuestionsSidebar: React.FC = () => {
    const { trackedQuestions, isLoading, experts, selectedExpertRoles, addErrorMessage } = useAgileBloomStore();
    const { updateQuestionStatusAndPotentiallyGenerateActions } = useAgileBloomChat();
    const [selectedQuestionIds, setSelectedQuestionIds] = useState<string[]>([]);
    const [isBulkUpdating, setIsBulkUpdating] = useState(false);

    const isProcessing = isLoading || isBulkUpdating;

    const handleDiscuss = (questionId: string) => {
      if (isProcessing) return;
      updateQuestionStatusAndPotentiallyGenerateActions(questionId, QuestionStatus.Addressing);
    };

    const handleMarkAddressed = (questionId: string) => {
      if (isProcessing) return;
      updateQuestionStatusAndPotentiallyGenerateActions(questionId, QuestionStatus.Addressed);
    };

    const handleDismiss = (questionId: string) => {
        if (isProcessing) return;
        updateQuestionStatusAndPotentiallyGenerateActions(questionId, QuestionStatus.Dismissed);
    };

    const handleToggleSelection = (id: string) => {
        setSelectedQuestionIds(prev =>
            prev.includes(id) ? prev.filter(qid => qid !== id) : [...prev, id]
        );
    };

    const handleSelectAllForExpert = (idsToAdd: string[]) => {
        setSelectedQuestionIds(prev => [...new Set([...prev, ...idsToAdd])]);
    };

    const handleDeselectAllForExpert = (idsToRemove: string[]) => {
        setSelectedQuestionIds(prev => prev.filter(id => !idsToRemove.includes(id)));
    };

    const handleBulkStatusChange = async (newStatus: QuestionStatus) => {
        if (isProcessing || selectedQuestionIds.length === 0) return;

        setIsBulkUpdating(true);
        try {
            const idsToProcess = [...selectedQuestionIds];
            const delay = (ms: number) => new Promise(res => setTimeout(res, ms));

            for (const [index, id] of idsToProcess.entries()) {
                // For actions that trigger AI calls, add a delay between them to avoid rate limits
                if (newStatus === QuestionStatus.Addressed || newStatus === QuestionStatus.Addressing) {
                    if (index > 0) { // No delay before the first call
                        await delay(BULK_ACTION_DELAY_MS);
                    }
                }
                await updateQuestionStatusAndPotentiallyGenerateActions(id, newStatus);
            }
        } catch (error) {
            console.error("Error during bulk update:", error);
            const message = error instanceof Error ? `Bulk update failed: ${error.message}` : "An unknown error occurred during bulk update.";
            addErrorMessage(message);
        } finally {
            setSelectedQuestionIds([]);
            setIsBulkUpdating(false);
        }
    };

    return (
        <div className="flex flex-col h-full w-full">
            <header className="p-4 border-b border-[#5c6f7e]">
                <h2 className="text-lg font-semibold text-[#e2a32d]">Tracked Discussion Points</h2>
                <p className="text-xs text-[#95aac0]">Questions raised by the AI team during discussion.</p>
            </header>

            <div className="flex-grow overflow-y-auto p-2 pb-32 scrollbar-thin scrollbar-thumb-[#5c6f7e] scrollbar-track-[#212934] space-y-3">
                {trackedQuestions.length > 0 && selectedExpertRoles.length > 0 ? (
                    selectedExpertRoles.map(expertRole => (
                      <ExpertQuestionGroup
                        key={expertRole}
                        expert={experts[expertRole]}
                        questions={trackedQuestions}
                        selectedQuestionIds={selectedQuestionIds}
                        onToggleSelection={handleToggleSelection}
                        onSelectAll={handleSelectAllForExpert}
                        onDeselectAll={handleDeselectAllForExpert}
                        onDiscuss={handleDiscuss}
                        onMarkAddressed={handleMarkAddressed}
                        onDismiss={handleDismiss}
                        isDisabled={isProcessing}
                      />
                    ))
                ) : (
                    <div className="flex flex-col items-center justify-center h-full text-center text-[#95aac0] p-4">
                        <Lightbulb size={40} className="mb-3 opacity-50" />
                        <h3 className="font-semibold text-gray-200">No Questions Found</h3>
                        <p className="text-xs mt-2">New questions will appear here as the AI team discusses the topic.</p>
                    </div>
                )}
            </div>

            {selectedQuestionIds.length > 0 && (
                 <div className="flex-shrink-0 p-3 border-t border-[#5c6f7e] bg-[#212934] animate-fadeIn">
                    <div className="flex justify-between items-center mb-2">
                        <h4 className="text-sm font-semibold text-gray-200">
                            Bulk Actions ({selectedQuestionIds.length} selected)
                        </h4>
                        <button 
                            onClick={() => setSelectedQuestionIds([])} 
                            disabled={isProcessing}
                            className="text-xs text-red-400 hover:text-red-300 disabled:opacity-50"
                        >
                            Deselect All
                        </button>
                    </div>
                    {isBulkUpdating && (
                        <div className="flex items-center justify-center p-2 text-yellow-400">
                             <Loader2 size={16} className="animate-spin mr-2" />
                             <span>Applying changes...</span>
                        </div>
                    )}
                    {!isBulkUpdating && (
                        <div className="grid grid-cols-1 sm:grid-cols-3 gap-2 text-xs">
                           <button 
                                onClick={() => handleBulkStatusChange(QuestionStatus.Addressing)} 
                                disabled={isProcessing}
                                className="flex items-center justify-center gap-1.5 p-2 bg-[#e2a32d]/20 hover:bg-[#e2a32d]/30 text-[#e2a32d] rounded-md transition-colors disabled:opacity-50 disabled:cursor-not-allowed"
                            >
                                <MessageSquare size={14}/> Discuss
                            </button>
                           <button 
                                onClick={() => handleBulkStatusChange(QuestionStatus.Addressed)} 
                                disabled={isProcessing}
                                className="flex items-center justify-center gap-1.5 p-2 bg-green-800/60 hover:bg-green-700/80 text-green-300 rounded-md transition-colors disabled:opacity-50 disabled:cursor-not-allowed"
                            >
                                <CheckSquare size={14}/> Mark Addressed
                            </button>
                             <button 
                                onClick={() => handleBulkStatusChange(QuestionStatus.Dismissed)}
                                disabled={isProcessing}
                                className="flex items-center justify-center gap-1.5 p-2 bg-red-800/60 hover:bg-red-700/80 text-red-300 rounded-md transition-colors disabled:opacity-50 disabled:cursor-not-allowed"
                            >
                                <XSquare size={14}/> Dismiss
                            </button>
                        </div>
                    )}
                </div>
            )}
        </div>
    );
};

import React, { useState, useRef, useEffect } from 'react';
import { TrackedQuestion, QuestionStatus } from '../types';
import { CheckCircle2, MessageSquare, Loader2, XSquare, MoreVertical, Trash2 } from 'lucide-react';

interface QuestionItemCardProps {
  question: TrackedQuestion;
  isSelected: boolean;
  onToggleSelection: (questionId: string) => void;
  onDiscuss: (questionId: string) => void;
  onMarkAddressed: (questionId: string) => void;
  onDismiss: (questionId: string) => void;
  isDisabled: boolean;
}

const statusConfig: Record<QuestionStatus, { icon: React.ReactNode; color: string; label: string }> = {
  [QuestionStatus.Open]: { icon: <MessageSquare size={14} />, color: 'text-[#95aac0]', label: 'Open' },
  [QuestionStatus.Addressing]: { icon: <Loader2 size={14} className="animate-spin" />, color: 'text-yellow-400', label: 'Addressing' },
  [QuestionStatus.Addressed]: { icon: <CheckCircle2 size={14} />, color: 'text-green-400', label: 'Addressed' },
  [QuestionStatus.Dismissed]: { icon: <XSquare size={14} />, color: 'text-gray-500', label: 'Dismissed' },
};

export const QuestionItemCard: React.FC<QuestionItemCardProps> = ({ question, isSelected, onToggleSelection, onDiscuss, onMarkAddressed, onDismiss, isDisabled }) => {
  const { id, expertRole, expertEmoji, text, status } = question;
  const config = statusConfig[status] || statusConfig.Open;

  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const menuRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (menuRef.current && !menuRef.current.contains(event.target as Node)) {
        setIsMenuOpen(false);
      }
    };
    document.addEventListener("mousedown", handleClickOutside);
    return () => {
      document.removeEventListener("mousedown", handleClickOutside);
    };
  }, []);

  const handleAction = (action: (id: string) => void) => {
    action(id);
    setIsMenuOpen(false);
  };

  return (
    <div
      className={`relative w-full text-left p-3 bg-[#333e48] rounded-lg border transition-all duration-200 flex gap-3 items-start
        ${isSelected ? 'border-[#e2a32d] shadow-lg' : 'border-[#5c6f7e]'}
        ${isDisabled ? 'opacity-60 cursor-not-allowed' : ''}
      `}
    >
      <input
        type="checkbox"
        checked={isSelected}
        onChange={() => onToggleSelection(id)}
        disabled={isDisabled}
        className="mt-1 h-4 w-4 rounded bg-[#5c6f7e] border-[#95aac0] text-[#c36e26] focus:ring-[#e2a32d] cursor-pointer disabled:cursor-not-allowed flex-shrink-0"
        aria-label={`Select question: ${text}`}
      />
      <div className="flex-grow">
        <div className="flex justify-between items-start mb-1.5">
            <div className="flex items-center text-xs text-[#95aac0]">
                <span className="mr-1.5 text-sm">{expertEmoji}</span>
                <span className="font-semibold text-gray-200">{expertRole}</span>
            </div>
        </div>
        <p className={`text-sm leading-snug ${status === QuestionStatus.Dismissed ? 'text-[#95aac0] line-through' : 'text-gray-200'}`}>{text}</p>
        <div className={`mt-2 flex items-center text-xs font-medium ${config.color}`}>
          {config.icon}
          <span className="ml-1.5">{config.label}</span>
        </div>
      </div>
      <div ref={menuRef} className="relative flex-shrink-0">
        <button
            onClick={(e) => { e.stopPropagation(); setIsMenuOpen(prev => !prev); }}
            disabled={isDisabled}
            className="p-1 -mr-1 -mt-1 rounded-full text-[#95aac0] hover:bg-[#5c6f7e] hover:text-[#e2a32d] transition-colors focus:outline-none focus:ring-2 focus:ring-[#e2a32d] disabled:cursor-not-allowed"
            title="Question actions"
        >
            <MoreVertical size={18} />
        </button>
        {isMenuOpen && (
            <div className="absolute top-full right-0 mt-2 w-48 bg-[#333e48] border border-[#5c6f7e] rounded-lg shadow-2xl z-50 animate-fadeIn">
                <ul className="py-1 text-sm text-gray-200">
                    <li className="px-3 py-1 text-xs text-[#95aac0]">Actions</li>
                    <li>
                        <button onClick={() => handleAction(onDiscuss)} className="w-full text-left flex items-center gap-2 px-3 py-2 hover:bg-[#e2a32d]/20 transition-colors">
                            <MessageSquare size={16} /> Discuss
                        </button>
                    </li>
                    <li>
                        <button onClick={() => handleAction(onMarkAddressed)} className="w-full text-left flex items-center gap-2 px-3 py-2 hover:bg-[#e2a32d]/20 transition-colors">
                            <CheckCircle2 size={16} /> Mark Addressed
                        </button>
                    </li>
                    <li>
                        <button onClick={() => handleAction(onDismiss)} className="w-full text-left flex items-center gap-2 px-3 py-2 text-red-400 hover:bg-red-900/50 transition-colors">
                            <Trash2 size={16} /> Dismiss
                        </button>
                    </li>
                </ul>
            </div>
        )}
      </div>
    </div>
  );
};

import React, { useMemo } from 'react';
import { TrackedTask, TaskStatus, ExpertRole, Expert, TaskPriority } from '../types';
import { Circle, Settings2, Check, Trash2, Play, Link, ChevronsUp, ChevronDown, ChevronsDown } from 'lucide-react';
import useAgileBloomStore from '../store/useAgileBloomStore';
import { ROLE_SCRUM_LEADER } from '../constants';

interface TaskItemCardProps {
  task: TrackedTask;
  onUpdate: (taskId: string, updates: Partial<Omit<TrackedTask, 'id'>>) => void;
  onRemove: (taskId: string) => void;
  onShowWork: (expert: ExpertRole) => void;
  isDisabled: boolean;
  selectedExpertRoles: ExpertRole[];
  experts: Record<ExpertRole, Expert>;
}

const statusConfig: Record<TaskStatus, { icon: React.ReactNode; color: string; }> = {
  [TaskStatus.ToDo]: { icon: <Circle size={14} />, color: 'text-[#95aac0]' },
  [TaskStatus.InProgress]: { icon: <Settings2 size={14} className="animate-spin" style={{ animationDuration: '3s' }} />, color: 'text-yellow-400' },
  [TaskStatus.Done]: { icon: <Check size={14} />, color: 'text-green-400' },
};

const priorityConfig: Record<TaskPriority, { icon: React.ReactNode; color: string; label: string }> = {
    'High': { icon: <ChevronsUp size={14} />, color: 'text-red-400', label: 'High' },
    'Medium': { icon: <ChevronDown size={14} />, color: 'text-yellow-400', label: 'Medium' },
    'Low': { icon: <ChevronsDown size={14} />, color: 'text-gray-400', label: 'Low' },
};

export const TaskItemCard: React.FC<TaskItemCardProps> = ({ task, onUpdate, onRemove, onShowWork, isDisabled, selectedExpertRoles, experts }) => {
    const { id, description, status, assignedTo, storyId, priority } = task;
    const { trackedStories } = useAgileBloomStore.getState();

    const statusCfg = statusConfig[status] || statusConfig[TaskStatus.ToDo];
    const priorityCfg = priorityConfig[priority] || priorityConfig.Medium;
    const expert = assignedTo ? experts[assignedTo] : null;

    const parentStory = storyId ? trackedStories.find(s => s.id === storyId) : null;

    const assignableExperts = useMemo(() => {
        return selectedExpertRoles.filter(role => role !== ROLE_SCRUM_LEADER);
    }, [selectedExpertRoles]);

    const handleAssign = (e: React.ChangeEvent<HTMLSelectElement>) => {
        const expertRole = e.target.value as ExpertRole;
        if (expertRole) {
            onUpdate(id, { assignedTo: expertRole });
        }
    };

    return (
        <div className="w-full text-left p-3 bg-[#333e48] rounded-lg border border-[#5c6f7e] transition-all duration-200 space-y-2">
             {parentStory && (
                <div className="text-xs text-[#e2a32d] flex items-center gap-1.5 bg-[#e2a32d]/20 px-2 py-1 rounded-full w-fit">
                   <Link size={12}/>
                   From Story: #{parentStory.id.substring(0, 6)}
                </div>
             )}
            <div className="flex justify-between items-start">
                <p className="text-sm text-gray-200 leading-snug flex-grow pr-2 whitespace-pre-wrap">{description}</p>
                <button
                    onClick={() => window.confirm(`Are you sure you want to remove this task?\n\n"${description}"`) && onRemove(id)}
                    disabled={isDisabled}
                    className="p-1 rounded-full text-gray-500 hover:bg-red-900/50 hover:text-red-400 transition-colors focus:outline-none focus:ring-2 focus:ring-red-500 disabled:cursor-not-allowed flex-shrink-0"
                    title="Remove task"
                    aria-label="Remove task"
                >
                    <Trash2 size={16} />
                </button>
            </div>

            <div className="mt-2 pt-2 border-t border-[#5c6f7e] flex justify-between items-center text-xs">
                <div className="flex items-center gap-3">
                     <span className={`flex items-center font-medium ${statusCfg.color}`}>
                        {statusCfg.icon}
                        <span className="ml-1.5">{status}</span>
                    </span>

                    <div className="relative group">
                        <button disabled={isDisabled} title="Set Priority" className={`flex items-center font-medium rounded px-1.5 py-0.5 ${priorityCfg.color} bg-black/20 hover:bg-black/40 disabled:cursor-not-allowed`}>
                            {priorityCfg.icon}
                            <span className="ml-1.5">{priorityCfg.label}</span>
                        </button>
                        <div className="absolute bottom-full mb-2 -left-2 w-32 bg-[#333e48] border border-[#5c6f7e] rounded-lg shadow-2xl z-50 hidden group-hover:block animate-fadeIn">
                            <ul className="py-1 text-sm text-gray-200">
                                {(['High', 'Medium', 'Low'] as TaskPriority[]).map(p => (
                                    <li key={p}>
                                        <button onClick={() => onUpdate(id, { priority: p })} className={`w-full text-left flex items-center gap-2 px-3 py-2 hover:bg-[#e2a32d]/20 transition-colors ${priorityConfig[p].color}`}>
                                            {priorityConfig[p].icon} {priorityConfig[p].label}
                                        </button>
                                    </li>
                                ))}
                            </ul>
                        </div>
                    </div>

                    {expert ? (
                        <span className="flex items-center text-[#95aac0]" title={`Assigned to ${expert.name}`}>
                            {expert.emoji}
                            <span className="ml-1 font-medium text-gray-200">{expert.name}</span>
                        </span>
                    ) : (
                         <select
                            value=""
                            onChange={handleAssign}
                            disabled={isDisabled || assignableExperts.length === 0}
                            className="bg-[#333e48] border border-[#5c6f7e] rounded text-xs py-0.5 px-2 focus:outline-none focus:ring-1 focus:ring-[#e2a32d] transition-colors disabled:cursor-not-allowed disabled:bg-[#333e48]/50 text-gray-200"
                            aria-label={`Assign task: ${description}`}
                            title={assignableExperts.length === 0 ? "No experts available to assign" : "Assign task"}
                        >
                            <option value="" disabled>Assign to...</option>
                            {assignableExperts.map(role => (
                                <option key={role} value={role}>
                                    {experts[role]?.emoji || '🧑‍💻'} {role}
                                </option>
                            ))}
                        </select>
                    )}
                </div>

                 <div className="flex items-center gap-2">
                    {task.status === TaskStatus.InProgress && task.assignedTo && (
                        <button
                            onClick={() => onShowWork(task.assignedTo!)}
                            disabled={isDisabled}
                            className="flex items-center gap-1 px-2 py-1 text-xs text-green-300 bg-green-900/40 hover:bg-green-800/60 rounded-md transition-colors disabled:opacity-50 disabled:cursor-not-allowed"
                            title={`Ask ${task.assignedTo} to show their work on this task`}
                        >
                            <Play size={12} />
                            Show Work
                        </button>
                    )}
                    <select
                        value={status}
                        onChange={(e) => onUpdate(id, { status: e.target.value as TaskStatus })}
                        disabled={isDisabled}
                        className="bg-[#5c6f7e] border border-[#95aac0] rounded text-xs py-0.5 px-1 focus:outline-none focus:ring-1 focus:ring-[#e2a32d] transition-colors disabled:cursor-not-allowed"
                        aria-label={`Change status for task: ${description}`}
                    >
                        {Object.values(TaskStatus).map(s => <option key={s} value={s}>{s}</option>)}
                    </select>
                </div>
            </div>
        </div>
    );
};

export enum AiProvider {
  Google = "Google",
  Mistral = "Mistral",
  OpenAI = "OpenAI",
  OpenRouter = "OpenRouter",
}

export interface AIConfig {
  provider: AiProvider;
  modelId: string;
  params: Record<string, any>;
  apiKeys: Partial<Record<AiProvider, string>>;
  useGeminiPreprocessing?: boolean;
}

export interface ModelParameter {
  id: 'temperature' | 'topP' | 'topK' | 'maxLength' | 'thinkingBudget';
  name: string;
  type: 'slider';
  min: number;
  max: number;
  step: number;
  defaultValue: number;
}


export interface AIModelConfig {
  id: string; // e.g., 'gemini-2.5-flash'
  name: string; // e.g., 'Gemini 2.5 Flash'
  provider: AiProvider;
  parameters: ModelParameter[];
  supportsVision: boolean;
  supportsSearch: boolean; 
  description: string;
  strengths: string[];
}


// Changed from enum to string to allow for custom roles
export type ExpertRole = string;

export interface Expert {
  name: ExpertRole;
  emoji: string;
  description:string;
  bgColor: string;
  textColor: string;
  isCustom?: boolean; // Flag to identify user-created experts
}

export interface SearchCitation {
  uri: string;
  title: string;
}

export interface FileEdit {
  path: string;
  content: string;
  explanation?: string;
  status: 'new' | 'modified' | 'deleted';
}

export interface DiscussionMessage {
  id: string;
  expert: Expert;
  text: string;
  thoughts?: string[];
  work?: string; // For code, markdown tables, etc.
  fileEdits?: FileEdit[]; // Proposed changes to the codebase
  isCommandResponse?: boolean;
  timestamp: number;
  isError?: boolean;
  searchCitations?: SearchCitation[] | null;
}

export interface Command {
  name: string;
  arguments: string;
  description: string;
  example?: string;
}

// New interfaces for auto-generation
export interface GeminiGeneratedTask {
  description: string;
  assignedTo?: ExpertRole;
}
export interface GeminiGeneratedStory {
  userStory: string;
  benefit: string;
  acceptanceCriteria: string[];
  priority?: StoryPriority;
  sprintPoints?: number;
}

// Matches the expected JSON output structure from Gemini
export interface GeminiResponseJson {
  expert: ExpertRole; 
  emoji: string;
  message: string;
  thoughts?: string[];
  work?: string;
  fileEdits?: FileEdit[];
  isCommandResponse?: boolean;
  memoryEntry?: string | null; 
  groundingData?: Array<{ web: { uri: string; title: string; } }> | null;
  tasks?: GeminiGeneratedTask[];
