const useAgileBloomStore = create<AgileBloomState>((set, get) => ({
  topic: null,
  discussion: [],
  isLoading: false,
  error: null,
  isHelpModalOpen: false,
  userMessageTimestamps: [],
  isRateLimited: false,
  isQuotaExceeded: false,
  memoryContext: [],
  uploadedFile: null,
  trackedQuestions: [],
  trackedTasks: [],
  trackedStories: [],
  isAutoModeEnabled: false,
  autoModeDelaySeconds: DEFAULT_AUTO_MODE_DELAY_SECONDS,
  settings: null,
  narrativeSummary: '',
  isSummaryLoading: false,
  experts: getInitialExperts(),
  selectedExpertRoles: [],
  lastActionWasAutoContinue: false,
  isConciseResponseMode: true,
  toggleConciseResponseMode: () => set((state) => ({ isConciseResponseMode: !state.isConciseResponseMode })),

  // Codebase state
  repoUrl: null,
  codebaseContext: null,
  codebaseImportStatus: 'idle',
  codebaseImportMessage: null,
  repoExcludePatterns: `# Dependency lock files\npackage-lock.json\nyarn.lock\n\n# Build output\n/dist/\n/build/\n\n# Logs\n*.log`,
  repoFiles: [],
  selectedRepoFiles: new Set(),
  proposedFileEdits: [],

  setCodebaseContext: (context) => set({ codebaseContext: context }),
  setTopic: (topic) => set({ topic, error: null }),
  addMessage: (message) => {
    const expert = get().experts[message.expertName] || get().experts[ROLE_SYSTEM];
    const newId = uuidv4();
    const newTimestamp = Date.now();
    const fullMessage: DiscussionMessage = { ...message, id: newId, timestamp: newTimestamp, expert };
    set((state) => ({
      discussion: [...state.discussion, fullMessage],
      isLoading: message.expertName !== ROLE_SYSTEM && message.expertName !== ROLE_USER ? state.isLoading : false, 
    }));
    return fullMessage; 
  },
  addErrorMessage: (text) => {
     set((state) => ({
      discussion: [
        ...state.discussion,
        { 
          id: uuidv4(), 
          expert: get().experts[ROLE_SYSTEM], 
          text, 
          timestamp: Date.now(),
          isError: true,
        },
      ],
      isLoading: false,
      error: text, 
    }));
  },
  setLoading: (loading) => set({ isLoading: loading }),
  setError: (error) => set({ error, isLoading: false }),
  clearChat: () => {
    set({ 
      discussion: [],
      topic: null, 
      error: null,
      userMessageTimestamps: [],
      isRateLimited: false,
      isQuotaExceeded: false,
      memoryContext: [],
      uploadedFile: null,
      trackedQuestions: [],
      trackedTasks: [],
      trackedStories: [],
      isAutoModeEnabled: false,
      autoModeDelaySeconds: DEFAULT_AUTO_MODE_DELAY_SECONDS,
      narrativeSummary: '',
      isSummaryLoading: false,
      selectedExpertRoles: [],
      lastActionWasAutoContinue: false,
    });
  },
  toggleHelpModal: () => set((state) => ({ isHelpModalOpen: !state.isHelpModalOpen })),
  addUserMessageTimestamp: (timestamp) => set((state) => ({
    userMessageTimestamps: [...state.userMessageTimestamps, timestamp],
  })),
  setRateLimitedStatus: (isLimited) => set({ isRateLimited: isLimited }),
  setQuotaExceeded: (isExceeded) => set({ isQuotaExceeded: isExceeded }),
  addMemoryEntry: (entry: string) => set((state) => {
    const newMemory = [...state.memoryContext, entry];
    return { memoryContext: newMemory.slice(-MAX_MEMORY_ENTRIES) }; 
  }),
  setUploadedFile: (file: UploadedFile | null) => set({ uploadedFile: file }),
  clearUploadedFile: () => set({ uploadedFile: null }),

  // Codebase Actions
  setRepoExcludePatterns: (patterns) => set({ repoExcludePatterns: patterns }),
  listRepoFiles: async (repoUrl) => {
      get().clearRepoData(); // Clear previous results before fetching new list
      set({ repoUrl, codebaseImportStatus: 'loading_list', codebaseImportMessage: 'Fetching repository file list...' });
      try {
          const files = await listGitHubRepoFiles(repoUrl, get().repoExcludePatterns);
          set({
              repoFiles: files,
              codebaseImportStatus: 'success_list',
              codebaseImportMessage: `Found ${files.length} files. Select files to include in context.`,
          });
          // User requested all de-selected by default
          get().toggleSelectAllRepoFiles(false); 
      } catch (error) {
          const message = error instanceof Error ? error.message : 'An unknown error occurred.';
          set({
              codebaseImportStatus: 'error',
              codebaseImportMessage: message,
          });
      }
  },
  confirmRepoFileSelection: async () => {
      const { selectedRepoFiles, repoUrl } = get();
      if (!repoUrl) return;

      if (selectedRepoFiles.size === 0) {
          set({
              codebaseContext: null,
              codebaseImportStatus: 'success_content',
              codebaseImportMessage: 'No files were selected. Codebase context is empty.',
          });
          return;
      }

      set({ codebaseImportStatus: 'loading_content', codebaseImportMessage: `Fetching content for ${selectedRepoFiles.size} selected file(s)...` });
      try {
          const { content: repoContent, fileCount } = await fetchGitHubFilesContent(repoUrl, Array.from(selectedRepoFiles));
          set({
              codebaseContext: repoContent,
              codebaseImportStatus: 'success_content',
              codebaseImportMessage: `Successfully added content from ${fileCount} file(s).`,
          });
      } catch (error) {
          const message = error instanceof Error ? error.message : 'An unknown error occurred.';
          set({
              codebaseContext: null,
              codebaseImportStatus: 'error',
              codebaseImportMessage: message,
          });
      }
  },
  toggleRepoFileSelection: (path, select) => {
    set(state => {
        const newSelected = new Set(state.selectedRepoFiles);
        const shouldSelect = select ?? !newSelected.has(path);
        if (shouldSelect) {
            newSelected.add(path);
        } else {
            newSelected.delete(path);
        }
        return { selectedRepoFiles: newSelected };
    });
  },
  toggleSelectAllRepoFiles: (select) => {
      set(state => {
          if (select) {
              const allPaths = state.repoFiles.map(f => f.path);
              return { selectedRepoFiles: new Set(allPaths) };
          }
          return { selectedRepoFiles: new Set() };
      });
  },
  clearRepoData: () => {
      set({
          repoUrl: null,
          codebaseContext: null,
          codebaseImportStatus: 'idle',
          codebaseImportMessage: null,
          repoFiles: [],
          selectedRepoFiles: new Set(),
      });
  },
  addProposedFileEdit: (edit) => set(state => ({ proposedFileEdits: [...state.proposedFileEdits, edit] })),
  clearProposedFileEdits: () => set({ proposedFileEdits: [] }),


  addTrackedQuestion: (questionData) => {
    const newQuestion: TrackedQuestion = {
      ...questionData,
      id: uuidv4(),
      timestamp: Date.now(),
      status: QuestionStatus.Open,
    };
    set((state) => ({
      trackedQuestions: [...state.trackedQuestions, newQuestion],
    }));
  },
  updateTrackedQuestionStatus: (id, status) => {
    set((state) => ({
      trackedQuestions: state.trackedQuestions.map((q) =>
        q.id === id ? { ...q, status } : q
      ),
    }));
  },
  removeTrackedQuestion: (id: string) => {
    set((state) => ({
        trackedQuestions: state.trackedQuestions.filter((q) => q.id !== id),
    }));
  },
  clearAllTrackedQuestions: () => set({ trackedQuestions: [] }),
  clearTrackedQuestionsByStatus: (statusToClear: QuestionStatus) => {
    set((state) => ({
        trackedQuestions: state.trackedQuestions.filter(q => q.status !== statusToClear),
    }));
  },

  addTrackedTask: (taskData) => {
    const currentTopic = get().topic || "General";
    const now = Date.now();
    const newTask: TrackedTask = {
      ...taskData,
      id: uuidv4(),
      timestamp: now,
      status: TaskStatus.ToDo,
      priority: 'Medium',
      order: now,
      topicContext: currentTopic,
    };
    set((state) => ({
      trackedTasks: [...state.trackedTasks, newTask],
    }));
  },
  updateTrackedTask: (taskId, updates) => {
    set((state) => ({
      trackedTasks: state.trackedTasks.map((task) =>
        task.id === taskId 
        ? { ...task, ...updates } 
        : task
      ),
    }));
  },
  removeTrackedTask: (taskId) => {
    set((state) => ({
      trackedTasks: state.trackedTasks.filter((task) => task.id !== taskId),
    }));
  },
  clearAllTrackedTasks: () => set({ trackedTasks: [] }),
  clearTrackedTasksByStatus: (statusToClear) => {
    set((state) => ({
      trackedTasks: state.trackedTasks.filter((task) => task.status !== statusToClear),
    }));
  },

  addTrackedStory: (storyData) => {
    const currentTopic = get().topic || "General";
    const newStory: TrackedStory = {
        ...storyData,
        id: uuidv4(),
        timestamp: Date.now(),
        status: StoryStatus.Backlog,
        priority: storyData.priority || 'Medium',
        topicContext: currentTopic,
    };
    set((state) => ({
        trackedStories: [...state.trackedStories, newStory],
    }));
  },
  updateTrackedStory: (storyId, updates) => {
    set(state => ({
        trackedStories: state.trackedStories.map(story => 
            story.id === storyId ? { ...story, ...updates } : story
        )
    }));
  },
  removeTrackedStory: (storyId) => {
      set((state) => ({
          trackedStories: state.trackedStories.filter((story) => story.id !== storyId),
      }));
  },
  clearAllTrackedStories: () => set({ trackedStories: [] }),
  clearTrackedStoriesByStatus: (status) => {
      set((state) => ({
          trackedStories: state.trackedStories.filter((story) => story.status !== status),
      }));
  },


  toggleAutoMode: () => set((state) => ({ isAutoModeEnabled: !state.isAutoModeEnabled })),
  setAutoModeDelaySeconds: (seconds: number) => set({ autoModeDelaySeconds: seconds }),
  importChatSession: (importedMessages: DiscussionMessage[]) => {
    set((state) => {
      // Find topic from imported messages
      let newTopic = 'Imported Session';
      const topicMessage = importedMessages.find(msg => msg.expert.name === ROLE_SYSTEM && msg.text.startsWith('Discussion started on topic:'));
      if (topicMessage) {
        const match = topicMessage.text.match(/topic: "([^"]+)"/);
        if (match && match[1]) {
          newTopic = match[1];
        }
      }

      // Re-hydrate experts that might not be in the default set
      const allExpertsInImport = importedMessages.reduce((acc, msg) => {
          if (!acc[msg.expert.name]) {
              acc[msg.expert.name] = msg.expert;
          }
          return acc;
      }, {} as Record<ExpertRole, Expert>);

      // Re-hydrate selected roles if possible, by looking at AI responses
      const importedRoles = importedMessages.reduce((acc, msg) => {
          if (msg.expert.name !== ROLE_USER && msg.expert.name !== ROLE_SYSTEM) {
              acc.add(msg.expert.name);
          }
          return acc;
      }, new Set<ExpertRole>());

      // Ensure Scrum Leader is present if any other experts are
      if (importedRoles.size > 0 && !importedRoles.has(ROLE_SCRUM_LEADER)) {
          const scrumLeaderExists = Object.values(allExpertsInImport).some(e => e.name === ROLE_SCRUM_LEADER);
          if (scrumLeaderExists) {
              importedRoles.add(ROLE_SCRUM_LEADER);
          }
      }

      const successMessage: DiscussionMessage = {
          id: uuidv4(),
          expert: state.experts[ROLE_SYSTEM] || DEFAULT_EXPERTS[ROLE_SYSTEM],
          text: `Successfully imported ${importedMessages.length} messages. Topic set to "${newTopic}". All tracked items (questions, tasks, stories) have been cleared.`,
          isCommandResponse: true,
          timestamp: Date.now(),
      };

      return {
        // Reset state
        topic: newTopic,
        error: null,
        userMessageTimestamps: [],
        isRateLimited: false,
        isQuotaExceeded: false,
        memoryContext: [],
        codebaseContext: null, // Also clear codebase on import
        uploadedFile: null,
        trackedQuestions: [], 
        trackedTasks: [],
        trackedStories: [],
        isAutoModeEnabled: false,
        autoModeDelaySeconds: DEFAULT_AUTO_MODE_DELAY_SECONDS,
        narrativeSummary: '',
        isSummaryLoading: false,
        lastActionWasAutoContinue: false,

        // Set imported data
        discussion: [...importedMessages, successMessage],
        // Merge imported experts with existing ones. Custom experts from localStorage will be preserved.
        experts: { ...state.experts, ...allExpertsInImport },
        selectedExpertRoles: Array.from(importedRoles),
      };
    });
  },
  setSettings: (settings) => set({ settings }),

  setNarrativeSummary: (summary) => set({ narrativeSummary: summary }),
  setSummaryLoading: (loading) => set({ isSummaryLoading: loading }),

  addExpert: (expert) => {
      const expertWithFlag = { ...expert, isCustom: true };
      set((state) => {
          const newExperts = { ...state.experts, [expert.name]: expertWithFlag };
          try {
              const currentCustom = JSON.parse(localStorage.getItem(AGILE_BLOOM_CUSTOM_EXPERTS_KEY) || '{}');
              currentCustom[expert.name] = expertWithFlag;
              localStorage.setItem(AGILE_BLOOM_CUSTOM_EXPERTS_KEY, JSON.stringify(currentCustom));
          } catch (error) {
              console.error("Failed to save custom expert to localStorage:", error);
          }
          return { experts: newExperts };
      });
  },
  removeExpert: (expertRole) => {
      set((state) => {
          const { [expertRole]: _, ...remainingExperts } = state.experts;
          try {
              const customExperts = JSON.parse(localStorage.getItem(AGILE_BLOOM_CUSTOM_EXPERTS_KEY) || '{}');
              delete customExperts[expertRole];
              localStorage.setItem(AGILE_BLOOM_CUSTOM_EXPERTS_KEY, JSON.stringify(customExperts));
          } catch (error) {
              console.error("Failed to remove custom expert from localStorage:", error);
          }
          return { experts: remainingExperts };
      });
  },
  setSelectedExpertRoles: (roles) => set({ selectedExpertRoles: roles }),
  setLastActionWasAutoContinue: (wasAuto) => set({ lastActionWasAutoContinue: wasAuto }),
}));

export default useAgileBloomStore;

import { GoogleGenAI, GenerateContentResponse, Part } from "@google/genai";
import { createMistral } from '@ai-sdk/mistral';
import { generateText } from 'ai';
import OpenAI from 'openai';
import { DiscussionMessage, Expert, ExpertRole, GeminiResponseJson, UploadedFile, AiProvider } from '../types';
import { INITIAL_SYSTEM_PROMPT_TEMPLATE, FISH_STORY_TASK_ANALYSIS_PROMPT, SUPPORTED_IMAGE_MIME_TYPES, ROLE_SCRUM_LEADER, ROLE_ENGINEER } from '../constants';
import { getModelConfigById } from './modelService';
import useAgileBloomStore from '../store/useAgileBloomStore';

// --- Helper Functions ---

const escapeForJsonString = (str: string | null | undefined): string => {
  if (!str) return "";
  // JSON.stringify escapes quotes, backslashes, newlines, and all control characters.
  // We slice to remove the outer quotes that stringify adds.
  return JSON.stringify(str).slice(1, -1);
};


function buildSystemPrompt(
  currentTopic: string | null,
  discussionHistory: DiscussionMessage[],
  memoryContext: string[],
  emulateExpertAs: ExpertRole | undefined,
  initialContext: string | null | undefined,
  assignedTasksContext: string | null | undefined,
  currentUserMessageOrCommand: string,
  isElaboration: boolean
): string {
    const { experts, selectedExpertRoles, isConciseResponseMode, codebaseContext } = useAgileBloomStore.getState();
    let emulationInstructions = "";
    let responsePersonaInstruction = "Determine who should respond based on the flow of an Agile Daily Scrum, the current user input/command, and conversation history.";
    let specificTaskInstructions = "";

    const activeExperts = selectedExpertRoles.map(role => experts[role]).filter(Boolean);
    const expertListForPrompt = activeExperts.map(expert => `- ${escapeForJsonString(expert.name)} (${expert.emoji}): ${escapeForJsonString(expert.description)}`).join('\n');

    if (emulateExpertAs) {
        const expertToEmulate = experts[emulateExpertAs];
        emulationInstructions = `\nYou are currently emulating: ${escapeForJsonString(expertToEmulate.name)} (${expertToEmulate.emoji}). Your response MUST be from this expert's perspective.`;
        responsePersonaInstruction = `You MUST respond as ${escapeForJsonString(expertToEmulate.name)}. The "expert" field in your JSON output MUST be "${escapeForJsonString(expertToEmulate.name)}".`;

        if (emulateExpertAs === ROLE_ENGINEER && codebaseContext) {
            specificTaskInstructions += `\n\nCODEBASE AGENT MODE: You have access to the project's codebase context. You are the designated agent for adding or editing files. If the user asks for code changes, or if you identify necessary edits, provide them in the 'fileEdits' array of your JSON response. For each edit, specify the full 'path', the new 'content', a brief 'explanation', and a 'status' (new, modified, or deleted).`;
        }

        if (emulateExpertAs === ROLE_SCRUM_LEADER) {
            if (currentUserMessageOrCommand.toLowerCase().includes("perform a fish analysis on the following item")) {
                specificTaskInstructions += `\nFollow these specific instructions for the FISH Analysis on the item provided by the user: \n${FISH_STORY_TASK_ANALYSIS_PROMPT}`;
            } else if (currentUserMessageOrCommand.toLowerCase().startsWith("/backlog")) {
                specificTaskInstructions += `\nUser command is /backlog. Provide a health check of the product backlog. In your main 'message', summarize the number of stories and tasks in each status. Point out any items that seem high-risk, poorly defined, or have been inactive for a long time. Suggest 1-2 items that might benefit from a detailed \`/analyze {id}\` command.`;
            }
        }
    }

    const formattedMemory = memoryContext.length > 0
        ? memoryContext.map(entry => `- ${escapeForJsonString(entry)}`).join('\n')
        : "No key points remembered yet.";

    const additionalContextSection = (initialContext && initialContext.trim() !== '')
        ? `\n--- Start of Additional Context ---\nThis initial context was provided by the user to set the stage for the entire discussion:\n\n${escapeForJsonString(initialContext.trim())}\n\n--- End of Additional Context ---\n`
        : "";

    const codebaseSection = (codebaseContext && codebaseContext.trim() !== '')
        ? `\n--- Start of Codebase Context ---\nThis is the content of the project's source code files provided for reference. You can reference or propose edits to these files.\n\n${escapeForJsonString(codebaseContext.trim())}\n--- End of Codebase Context ---\n`
        : "";

    const assignedTasksSection = (assignedTasksContext && assignedTasksContext.trim() !== '')
        ? `\n--- Start of Your Assigned Tasks ---\nThis is a list of tasks currently assigned to you. When responding to commands like /show-work, please focus your response on these tasks.\n\n${escapeForJsonString(assignedTasksContext.trim())}\n--- End of Your Assigned Tasks ---\n`
        : "";

    let concisenessInstruction = "";
    if (isElaboration) {
        concisenessInstruction = "The user has asked you to elaborate. Provide a detailed and comprehensive response, ignoring any previous instructions about conciseness. There are no word or sentence limits for this response.";
    } else if (isConciseResponseMode) {
        concisenessInstruction = "IMPORTANT: Your main 'message' response MUST be concise, containing no more than 47 words AND no more than 2 sentences. Be direct and to the point. You can provide more detailed analysis or tangential ideas in your 'thoughts' array if needed.";
    }

    const historyFormatter = (discussion: DiscussionMessage[], maxTurns = 10): string => {
        return discussion.slice(-maxTurns).map(msg => `${escapeForJsonString(msg.expert.name)} (${msg.expert.emoji}): ${escapeForJsonString(msg.text)}${msg.work ? `\nWORK:\n${escapeForJsonString(msg.work)}` : ''}${msg.searchCitations && msg.searchCitations.length > 0 ? `\n(Sources: ${escapeForJsonString(msg.searchCitations.map(c => c.title).join(', '))})` : ''}`).join('\n\n');
    }

    return INITIAL_SYSTEM_PROMPT_TEMPLATE
        .replace('{input_topic}', escapeForJsonString(currentTopic) || "No topic set yet. Await user to set a topic with /topic command.")
        .replace('{history}', historyFormatter(discussionHistory))
        .replace('{{emulation_instructions}}', emulationInstructions)
        .replace('{{response_persona_instruction}}', responsePersonaInstruction)
        .replace('{{specific_task_instructions}}', specificTaskInstructions)
        .replace('{persistent_memory_context}', formattedMemory)
        .replace('{{additional_context_section}}', additionalContextSection + codebaseSection)
        .replace('{{assigned_tasks_section}}', assignedTasksSection)
        .replace('{{conciseness_instruction}}', concisenessInstruction)
        .replace('{expert_list}', expertListForPrompt);
}

const MAX_RETRIES = 3;
const INITIAL_DELAY_MS = 1000;

async function withRetry<T>(fn: () => Promise<T>): Promise<T> {
    let retries = 0;
    let lastError: Error | null = null;
    while (retries <= MAX_RETRIES) {
        try {
            return await fn();
        } catch (error) {
            lastError = error instanceof Error ? error : new Error(String(error));
            const errorMessage = lastError.message.toLowerCase();
            console.error(`Error calling AI API (Attempt ${retries + 1}/${MAX_RETRIES + 1}):`, lastError);

            if (errorMessage.includes('quota')) {
                console.error("Quota exceeded error detected. Halting further API requests.");
                throw new Error("Failed to call the AI API, quota exceeded. Please try again later.");
            }
            if (retries === MAX_RETRIES) {
                throw new Error(`AI API Error (Max retries reached): ${lastError.message}`);
            }
            const delay = INITIAL_DELAY_MS * (2 ** retries) + Math.random() * 1000;
            console.log(`Retrying AI API call in ${delay.toFixed(0)}ms...`);
            await new Promise(resolve => setTimeout(resolve, delay));
            retries++;
        }
    }
    throw new Error(lastError?.message || "AI API Error: Exhausted retries but did not return or throw explicitly from loop.");
}

function parseJsonResponse(rawResponseText: string): GeminiResponseJson {
    let jsonStr = rawResponseText.trim();
    const fenceRegex = /^```(\w*)?\s*\n?(.*?)\n?\s*```$/s;
    const match = jsonStr.match(fenceRegex);
    if (match?.[2]) {
        jsonStr = match[2].trim();
    }
    return JSON.parse(jsonStr) as GeminiResponseJson;
}

// --- Provider-Specific Implementations ---

async function generateGeminiResponse(
  apiKey: string,
  modelId: string,
  systemPromptText: string,
  userMessage: string,
  useGoogleSearch: boolean,
  params: Record<string, any>,
  uploadedImageFile?: UploadedFile | null,
): Promise<GeminiResponseJson> {
  const geminiAi = new GoogleGenAI({ apiKey });
  const contentParts: Part[] = [];

  if (uploadedImageFile?.base64Data && SUPPORTED_IMAGE_MIME_TYPES.includes(uploadedImageFile.mimeType)) {
      contentParts.push({ inlineData: { mimeType: uploadedImageFile.mimeType, data: uploadedImageFile.base64Data } });
  }
  contentParts.push({ text: userMessage || "Please analyze the provided content." });

  const { temperature, topP, topK, thinkingBudget, maxLength } = params;
  const geminiConfig: any = {
    systemInstruction: systemPromptText,
    tools: useGoogleSearch ? [{ googleSearch: {} }] : undefined,
    responseMimeType: useGoogleSearch ? undefined : "application/json",
    temperature: temperature,
    topP: topP,
    topK: topK,
  };

  if (maxLength !== undefined) {
    geminiConfig.maxOutputTokens = maxLength;
  }

  if (thinkingBudget !== undefined && modelId.includes('flash')) {
    geminiConfig.thinkingConfig = { thinkingBudget: thinkingBudget };
  }

  const response: GenerateContentResponse = await geminiAi.models.generateContent({
      model: modelId,
      contents: { parts: contentParts },
      config: geminiConfig,
  });

  const parsedData = parseJsonResponse(response.text);

  if (useGoogleSearch && response.candidates?.[0]?.groundingMetadata?.groundingChunks) {
      parsedData.groundingData = response.candidates[0].groundingMetadata.groundingChunks
          .filter(chunk => chunk.web?.uri && chunk.web?.title)
          .map(chunk => ({ web: { uri: chunk.web!.uri!, title: chunk.web!.title! } }));
  }
  return parsedData;
}

async function generateMistralResponse(
    apiKey: string,
    modelId: string,
    systemPromptText: string,
    userMessage: string,
    params: Record<string, any>,
): Promise<GeminiResponseJson> {
    const mistralProvider = createMistral({ apiKey });
    const { text } = await generateText({
        model: mistralProvider(modelId),
        system: systemPromptText,
        messages: [{ role: 'user', content: userMessage }],
        temperature: params.temperature,
    });
    return parseJsonResponse(text);
}

async function generateOpenAiResponse(
    apiKey: string,
    modelId: string,
    systemPromptText: string,
    userMessage: string,
    uploadedImageFile: UploadedFile | null,
    params: Record<string, any>
): Promise<GeminiResponseJson> {
    const openai = new OpenAI({ apiKey, dangerouslyAllowBrowser: true });

    const messages: OpenAI.Chat.Completions.ChatCompletionMessageParam[] = [
        { role: 'system', content: systemPromptText },
    ];

    const userContent: OpenAI.Chat.Completions.ChatCompletionContentPart[] = [{ type: 'text', text: userMessage }];
    if (uploadedImageFile?.base64Data && SUPPORTED_IMAGE_MIME_TYPES.includes(uploadedImageFile.mimeType)) {
        userContent.push({
            type: 'image_url',
            image_url: { url: `data:${uploadedImageFile.mimeType};base64,${uploadedImageFile.base64Data}` }
        });
    }
    messages.push({ role: 'user', content: userContent });

    const response = await openai.chat.completions.create({
        model: modelId,
        messages: messages,
        response_format: { type: 'json_object' },
        temperature: params.temperature,
        top_p: params.topP,
    });

    const responseText = response.choices[0]?.message?.content;
    if (!responseText) throw new Error("OpenAI response was empty.");
    return JSON.parse(responseText) as GeminiResponseJson;
}

async function generateOpenRouterResponse(
    apiKey: string,
    modelId: string,
    systemPromptText: string,
    userMessage: string,
    uploadedImageFile: UploadedFile | null,
    params: Record<string, any>
): Promise<GeminiResponseJson> {
    const openrouter = new OpenAI({ 
        apiKey, 
        baseURL: "https://openrouter.ai/api/v1",
        dangerouslyAllowBrowser: true 
    });

    const messages: OpenAI.Chat.Completions.ChatCompletionMessageParam[] = [
        { role: 'system', content: systemPromptText },
    ];

    const userContent: OpenAI.Chat.Completions.ChatCompletionContentPart[] = [{ type: 'text', text: userMessage }];
    if (uploadedImageFile?.base64Data && SUPPORTED_IMAGE_MIME_TYPES.includes(uploadedImageFile.mimeType)) {
        userContent.push({
            type: 'image_url',
            image_url: { url: `data:${uploadedImageFile.mimeType};base64,${uploadedImageFile.base64Data}` }
        });
    }
    messages.push({ role: 'user', content: userContent });

    const response = await openrouter.chat.completions.create({
        model: modelId,
        messages: messages,
        response_format: { type: 'json_object' },
        temperature: params.temperature,
    });

    const responseText = response.choices[0]?.message?.content;
    if (!responseText) throw new Error("OpenRouter response was empty.");
    return JSON.parse(responseText) as GeminiResponseJson;
